def compress(s):
    if not s:
        return ''

    result = []
    count = 1
    current_char = s[0]

    for i in range(1, len(s)):
        if s[i] == current_char:
            count += 1
        else:
            result.append(current_char + str(count))
            current_char = s[i]
            count = 1

    result.append(current_char + str(count))
    return ''.join(result)
