def caesar(s, k):
    result = []
    k = k % 26  # Normalize k to be within 0-25 range

    for char in s:
        if char.isalpha():
            # Determine the base ASCII value ('A' for uppercase, 'a' for lowercase)
            base = ord('A') if char.isupper() else ord('a')
            # Shift the character and wrap around using modulo 26
            shifted = (ord(char) - base + k) % 26
            result.append(chr(base + shifted))
        else:
            # Non-alphabetic characters remain unchanged
            result.append(char)

    return ''.join(result)
```

